&lt;h1 data-start=&quot;242&quot; data-end=&quot;299&quot;&gt;&lt;strong data-start=&quot;244&quot; data-end=&quot;297&quot;&gt;Assistant Market Manager – Retail Direct Engagement Program&lt;/strong&gt;&lt;/h1&gt;
&lt;p data-start=&quot;300&quot; data-end=&quot;553&quot;&gt;&lt;strong data-start=&quot;300&quot; data-end=&quot;313&quot;&gt;Location:&lt;/strong&gt; Austin, TX (In-Market Role | Up to 40-mile radius from Austin, TX)&lt;br data-start=&quot;389&quot; data-end=&quot;392&quot;&gt;&lt;br data-start=&quot;460&quot; data-end=&quot;463&quot;&gt;&lt;/p&gt;
